 Begin CmpMap 	# Compound Mapping
    Nin = 1 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    MapA = 	# First component Mapping
       Begin CmpMap 	# Compound Mapping
          Nin = 1 	# Number of input coordinates
       IsA Mapping 	# Mapping between coordinate systems
          MapA = 	# First component Mapping
             Begin TranMap 	# Compound Transformation Mapping
                Nin = 1 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
                MapA = 	# Mapping for forward transformation
                   Begin ZoomMap 	# Zoom about the origin
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Zoom = 2 	# Zoom factor
                   End ZoomMap
                MapB = 	# Mapping for inverse transformation
                   Begin ZoomMap 	# Zoom about the origin
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Zoom = 0.5 	# Zoom factor
                   End ZoomMap
             End TranMap
          MapB = 	# Second component Mapping
             Begin TranMap 	# Compound Transformation Mapping
                Nin = 1 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
                MapA = 	# Mapping for forward transformation
                   Begin ZoomMap 	# Zoom about the origin
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Zoom = 3 	# Zoom factor
                   End ZoomMap
                MapB = 	# Mapping for inverse transformation
                   Begin ZoomMap 	# Zoom about the origin
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Zoom = 0.33333333333333331 	# Zoom factor
                   End ZoomMap
             End TranMap
       End CmpMap
    MapB = 	# Second component Mapping
       Begin ZoomMap 	# Zoom about the origin
          Nin = 1 	# Number of input coordinates
       IsA Mapping 	# Mapping between coordinate systems
          Zoom = 5 	# Zoom factor
       End ZoomMap
 End CmpMap
